  8â†’import kotlinx.datetime.internal.*
  9â†’import kotlinx.datetime.format.*
 10â†’import kotlinx.datetime.serializers.UtcOffsetSerializer
 11â†’import kotlinx.serialization.Serializable
 12â†’import kotlin.math.abs
 13â†’
 14â†’@Serializable(with = UtcOffsetSerializer::class)
 15â†’public actual class UtcOffset private constructor(public actual val totalSeconds: Int) {
 16â†’
 17â†’    override fun hashCode(): Int = totalSeconds
 18â†’    override fun equals(other: Any?): Boolean = other is UtcOffset && this.totalSeconds == other.totalSeconds
 19â†’    actual override fun toString(): String = format(Formats.ISO)
 20â†’
 21â†’    public actual companion object {
 22â†’
 23â†’        public actual val ZERO: UtcOffset = UtcOffset(totalSeconds = 0)
 24â†’
 25â†’        public actual fun parse(input: CharSequence, format: DateTimeFormat<UtcOffset>): UtcOffset = format.parse(input)
 26â†’
 27â†’        @Deprecated("This overload is only kept for binary compatibility", level = DeprecationLevel.HIDDEN)
 28â†’        public fun parse(offsetString: String): UtcOffset = parse(input = offsetString)
 29â†’
 30â†’        private fun validateTotal(totalSeconds: Int) {
 31â†’            if (totalSeconds !in -18 * SECONDS_PER_HOUR .. 18 * SECONDS_PER_HOUR) {
 32â†’                throw IllegalArgumentException("Total seconds value is out of range: $totalSeconds")
 33â†’            }
 34â†’        }
 35â†’
 36â†’        // org.threeten.bp.ZoneOffset#validate
 37â†’        private fun validate(hours: Int, minutes: Int, seconds: Int) {
 38â†’            if (hours < -18 || hours > 18) {
 39â†’                throw IllegalArgumentException("Zone offset hours not in valid range: value " + hours +
 40â†’                        " is not in the range -18 to 18")
 41â†’            }
 42â†’            if (hours > 0) {
 43â†’                if (minutes < 0 || seconds < 0) {
 44â†’                    throw IllegalArgumentException("Zone offset minutes and seconds must be positive because hours is positive")
 45â†’                }
 46â†’            } else if (hours < 0) {
 47â†’                if (minutes > 0 || seconds > 0) {
 48â†’                    throw IllegalArgumentException("Zone offset minutes and seconds must be negative because hours is negative")
 49â†’                }
 50â†’            } else if (minutes > 0 && seconds < 0 || minutes < 0 && seconds > 0) {
 51â†’                throw IllegalArgumentException("Zone offset minutes and seconds must have the same sign")
 52â†’            }
 53â†’            if (abs(minutes) > 59) {
 54â†’                throw IllegalArgumentException("Zone offset minutes not in valid range: abs(value) " +
 55â†’                        abs(minutes) + " is not in the range 0 to 59")
 56â†’            }
 57â†’            if (abs(seconds) > 59) {
 58â†’                throw IllegalArgumentException("Zone offset seconds not in valid range: abs(value) " +
 59â†’                        abs(seconds) + " is not in the range 0 to 59")
 60â†’            }
 61â†’            if (abs(hours) == 18 && (abs(minutes) > 0 || abs(seconds) > 0)) {
 62â†’                throw IllegalArgumentException("Utc offset not in valid range: -18:00 to +18:00")
 63â†’            }
 64â†’        }
 65â†’
 66â†’        // org.threeten.bp.ZoneOffset#ofHoursMinutesSeconds
 67â†’        internal fun ofHoursMinutesSeconds(hours: Int, minutes: Int, seconds: Int): UtcOffset {
 68â†’            validate(hours, minutes, seconds)
 69â†’            return if (hours == 0 && minutes == 0 && seconds == 0) ZERO
 70â†’            else ofSeconds(hours * SECONDS_PER_HOUR + minutes * SECONDS_PER_MINUTE + seconds)
 71â†’        }
 72â†’
 73â†’        // org.threeten.bp.ZoneOffset#ofTotalSeconds
 74â†’        internal fun ofSeconds(seconds: Int): UtcOffset {
 75â†’            validateTotal(seconds)
 76â†’            return if (seconds % (15 * SECONDS_PER_MINUTE) == 0) {
 77â†’                utcOffsetCache[seconds] ?: UtcOffset(totalSeconds = seconds).also { utcOffsetCache[seconds] = it }
 78â†’            } else {
 79â†’                UtcOffset(totalSeconds = seconds)
 80â†’            }
 81â†’        }
 82â†’
 83â†’        @Suppress("FunctionName")
 84â†’        public actual fun Format(block: DateTimeFormatBuilder.WithUtcOffset.() -> Unit): DateTimeFormat<UtcOffset> =
 85â†’            UtcOffsetFormat.build(block)
 86â†’    }
 87â†’
 88â†’    public actual object Formats {
 89â†’        public actual val ISO: DateTimeFormat<UtcOffset> get() = ISO_OFFSET
 90â†’        public actual val ISO_BASIC: DateTimeFormat<UtcOffset> get() = ISO_OFFSET_BASIC
 91â†’        public actual val FOUR_DIGITS: DateTimeFormat<UtcOffset> get() = FOUR_DIGIT_OFFSET
 92â†’    }
 93â†’}
 94â†’
 95â†’@ThreadLocal
 96â†’private var utcOffsetCache: MutableMap<Int, UtcOffset> = mutableMapOf()
 97â†’
 98â†’@Suppress("ACTUAL_FUNCTION_WITH_DEFAULT_ARGUMENTS")
 99â†’public actual fun UtcOffset(hours: Int? = null, minutes: Int? = null, seconds: Int? = null): UtcOffset =
100â†’    when {
101â†’        hours != null ->
102â†’            UtcOffset.ofHoursMinutesSeconds(hours, minutes ?: 0, seconds ?: 0)
103â†’        minutes != null ->
104â†’            UtcOffset.ofHoursMinutesSeconds(minutes / MINUTES_PER_HOUR, minutes % MINUTES_PER_HOUR, seconds ?: 0)
105â†’        else -> {
106â†’            UtcOffset.ofSeconds(seconds ?: 0)
107â†’        }
108â†’    }
