 93â†’internal fun DateTimeFormatBuilder.WithUtcOffset.isoOffset(
 94â†’    zOnZero: Boolean,
 95â†’    useSeparator: Boolean,
 96â†’    outputMinute: WhenToOutput,
 97â†’    outputSecond: WhenToOutput
 98â†’) {
 99â†’    require(outputMinute >= outputSecond) { "Seconds cannot be included without minutes" }
100â†’    fun DateTimeFormatBuilder.WithUtcOffset.appendIsoOffsetWithoutZOnZero() {
101â†’        offsetHours()
102â†’        outputIfNeeded(outputMinute) {
103â†’            if (useSeparator) {
104â†’                char(':')
105â†’            }
106â†’            offsetMinutesOfHour()
107â†’            outputIfNeeded(outputSecond) {
108â†’                if (useSeparator) {
109â†’                    char(':')
110â†’                }
111â†’                offsetSecondsOfMinute()
112â†’            }
113â†’        }
114â†’    }
115â†’    if (zOnZero) {
116â†’        optional("Z") {
117â†’            alternativeParsing({
118â†’                char('z')
119â†’            }) {
120â†’                appendIsoOffsetWithoutZOnZero()
121â†’            }
122â†’        }
123â†’    } else {
124â†’        appendIsoOffsetWithoutZOnZero()
125â†’    }
126â†’}
