193â†’internal class UtcOffsetWholeHoursDirective(private val padding: Padding) :
194â†’    UnsignedIntFieldFormatDirective<UtcOffsetFieldContainer>(
195â†’        OffsetFields.totalHoursAbs,
196â†’        minDigits = padding.minDigits(2),
197â†’        spacePadding = padding.spaces(2)
198â†’    ) {
199â†’
200â†’    override val builderRepresentation: String
201â†’        get() =
202â†’            "${DateTimeFormatBuilder.WithUtcOffset::offsetHours.name}(${padding.toKotlinCode()})"
203â†’
204â†’    override fun equals(other: Any?): Boolean = other is UtcOffsetWholeHoursDirective && padding == other.padding
