  6â†’package kotlinx.datetime.internal.format
  7â†’
  8â†’import kotlinx.datetime.internal.format.formatter.*
  9â†’import kotlinx.datetime.internal.format.parser.*
 10â†’
 11â†’internal sealed interface FormatStructure<in T> {
 12â†’    fun parser(): ParserStructure<T>
 13â†’    fun formatter(): FormatterStructure<T>
 14â†’}
 15â†’
 16â†’internal class BasicFormatStructure<in T>(
 17â†’    val directive: FieldFormatDirective<T>
 18â†’) : NonConcatenatedFormatStructure<T> {
 19â†’    override fun toString(): String = "BasicFormatStructure($directive)"
 20â†’
 21â†’    override fun equals(other: Any?): Boolean = other is BasicFormatStructure<*> && directive == other.directive
 22â†’    override fun hashCode(): Int = directive.hashCode()
 23â†’
 24â†’    override fun parser(): ParserStructure<T> = directive.parser()
 25â†’    override fun formatter(): FormatterStructure<T> = directive.formatter()
 26â†’}
 27â†’
 28â†’internal class ConstantFormatStructure<in T>(
 29â†’    val string: String
 30â†’) : NonConcatenatedFormatStructure<T> {
 31â†’    override fun toString(): String = "ConstantFormatStructure($string)"
 32â†’
 33â†’    override fun equals(other: Any?): Boolean = other is ConstantFormatStructure<*> && string == other.string
 34â†’    override fun hashCode(): Int = string.hashCode()
 35â†’
 36â†’    override fun parser(): ParserStructure<T> = ParserStructure(
 37â†’        operations = when {
 38â†’            string.isEmpty() -> emptyList()
 39â†’            else -> buildList {
 40â†’                val suffix = if (string[0].isDigit()) {
 41â†’                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile { it.isDigit() }))))
 42â†’                    string.dropWhile { it.isDigit() }
 43â†’                } else {
 44â†’                    string
 45â†’                }
 46â†’                if (suffix.isNotEmpty()) {
 47â†’                    if (suffix[suffix.length - 1].isDigit()) {
 48â†’                        add(PlainStringParserOperation(suffix.dropLastWhile { it.isDigit() }))
 49â†’                        add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(suffix.takeLastWhile { it.isDigit() }))))
 50â†’                    } else {
 51â†’                        add(PlainStringParserOperation(suffix))
 52â†’                    }
 53â†’                }
 54â†’            }
 55â†’        },
 56â†’        followedBy = emptyList()
 57â†’    )
 58â†’
 59â†’    override fun formatter(): FormatterStructure<T> = ConstantStringFormatterStructure(string)
 60â†’}
 61â†’
 62â†’internal class SignedFormatStructure<in T>(
 63â†’    val format: FormatStructure<T>,
 64â†’    val withPlusSign: Boolean,
 65â†’) : NonConcatenatedFormatStructure<T> {
 66â†’
 67â†’    private val fieldSigns = basicFormats(format).mapNotNull { it.field.sign }.toSet()
 68â†’
 69â†’    init {
 70â†’        require(fieldSigns.isNotEmpty()) { "Signed format must contain at least one field with a sign" }
 71â†’    }
 72â†’
 73â†’    override fun toString(): String = "SignedFormatStructure($format)"
 74â†’
 75â†’    override fun equals(other: Any?): Boolean =
 76â†’        other is SignedFormatStructure<*> && format == other.format && withPlusSign == other.withPlusSign
 77â†’
 78â†’    override fun hashCode(): Int = 31 * format.hashCode() + withPlusSign.hashCode()
 79â†’
 80â†’    override fun parser(): ParserStructure<T> = listOf(
 81â†’        ParserStructure(
 82â†’            operations = listOf(
 83â†’                SignParser(
 84â†’                    isNegativeSetter = { value, isNegative ->
 85â†’                        for (field in fieldSigns) {
 86â†’                            val wasNegative = field.isNegative.getter(value) == true
 87â†’                            // TODO: replacing `!=` with `xor` fails on JS
 88â†’                            field.isNegative.trySetWithoutReassigning(value, isNegative != wasNegative)
 89â†’                        }
 90â†’                    },
 91â†’                    withPlusSign = withPlusSign,
 92â†’                    whatThisExpects = "sign for ${this.fieldSigns}"
 93â†’                )
 94â†’            ),
 95â†’            emptyList()
 96â†’        ), format.parser()
 97â†’    ).concat()
 98â†’
 99â†’    override fun formatter(): FormatterStructure<T> {
100â†’        val innerFormat = format.formatter()
101â†’        fun checkIfAllNegative(value: T): Boolean {
102â†’            var seenNonZero = false
103â†’            for (check in fieldSigns) {
104â†’                when {
105â†’                    check.isNegative.getter(value) == true -> seenNonZero = true
106â†’                    check.isZero(value) -> continue
107â†’                    else -> return false
108â†’                }
109â†’            }
110â†’            return seenNonZero
111â†’        }
112â†’        return SignedFormatter(
113â†’            innerFormat,
114â†’            ::checkIfAllNegative,
115â†’            withPlusSign
116â†’        )
117â†’    }
118â†’}
